const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let n;
let hand = [];
let k;
readline.on('line', line => {
    if (i === 0) {
        n = parseInt(line);
    } else if (i <= n) {
        hand.push(parseInt(line));
    } else if (i === n + 1) {
        k = parseInt(line);
        hand.sort((a, b) => a - b);
        const solution = new Solution();
        console.log(solution.solve(hand, k) ? "Yes" : "No");
        readline.close();
    }
    i++;
});

