#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    cin >> n;
    map<int, int> cnt;
    for(int i = 0; i < n; i++){
        int x;
        cin >> x;
        cnt[x]++;
    }
    int k;
    cin >> k;
    for(auto it = cnt.begin(); it != cnt.end(); it++){
        while(it->second > 0){
            for(int i = it->first; i < it->first + k; i++){
                if(cnt.find(i) == cnt.end() || --cnt[i] < 0){
                    cout << "No" << endl;
                    return 0;
                }
            }
        }
    }
    cout << "Yes" << endl;
    return 0;
}
